import fs from 'node:fs/promises';
import {
  FEEDS_JS_PATH,
  buildFrontEndFeedsFromJson,
  readFeedsJson
} from './feed-config-common.mjs';

function buildFeedsJsContent(feedsObject) {
  const json = JSON.stringify(feedsObject, null, 2);

  return `/**
 * Auto-generated from feeds.json.
 *
 * Do not edit this file manually unless you intentionally want
 * the frontend feed list to diverge from feeds.json.
 *
 * Regenerate with:
 *   npm run sync:feeds
 */
const FEEDS = ${json};

// Export for use in index.html
if (typeof window !== 'undefined') {
  window.FEEDS = FEEDS;
}
`;
}

async function main() {
  const force = process.argv.includes('--force');

  const jsonConfig = await readFeedsJson();
  const feedsForFrontend = buildFrontEndFeedsFromJson(jsonConfig);
  const output = buildFeedsJsContent(feedsForFrontend);

  if (!force) {
    console.log('⚠️ Dry-run only. No files were changed.');
    console.log('Run with --force to write: node scripts/generate-feeds-js.mjs --force');
    return;
  }

  await fs.writeFile(FEEDS_JS_PATH, output, 'utf8');

  console.log('✅ Generated public/feeds.js from feeds.json');
}

main().catch(error => {
  console.error('❌ Failed to generate public/feeds.js:', error?.message || error);
  process.exit(1);
});
